95	void merge_sort_items(std::vector<int>& items_to_sort, int left, int right) {
96	    if (left < right) {
97	        int mid = left + (right - left) / 2;
98	        merge_sort_items(items_to_sort, left, mid);
99	        merge_sort_items(items_to_sort, mid + 1, right);
100	        merge_for_sort(items_to_sort, left, mid, right);
101	    }
102	}
