130	int main() {
131	    std::ios_base::sync_with_stdio(false);
132	    std::cin.tie(NULL);
133	
134	    program_start_time = std::chrono::steady_clock::now();
135	    uint64_t random_seed = std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::steady_clock::now().time_since_epoch()).count();
136	    rng_engine.seed(random_seed);
137	
138	    std::cin >> N_items_global >> D_groups_global >> Q_total_global;
139	
140	    // Reserve queries for group-comparison refinement phase
141	    // Binary search refinement is more effective, so allocate more budget
142	    // Each round costs ~2*(D-1) + 1 + log2(group_size) queries
143	    int avg_group_size = N_items_global / std::max(1, D_groups_global);
144	    int queries_per_round = 2 * (D_groups_global - 1) + 1 + (int)std::ceil(std::log2(std::max(2, avg_group_size)));
145	    int desired_rounds = std::min(50, D_groups_global * 5);
146	    int refinement_budget = std::min(Q_total_global * 2 / 5, queries_per_round * desired_rounds);
147	    refinement_budget = std::max(refinement_budget, std::min(Q_total_global / 3, D_groups_global * 10));
148	    int estimation_budget = Q_total_global - refinement_budget;
149	
150	    std::vector<long long> estimated_weights(N_items_global);
151	
152	    // Determine how many pivots we can sort within estimation budget
153	    int k_pivots_chosen = 0;
154	    if (N_items_global > 0) {
155	        for (int cur_k_val = N_items_global; cur_k_val >= 1; --cur_k_val) {
156	            if (calculate_estimated_query_cost(N_items_global, cur_k_val) <= estimation_budget) {
157	                k_pivots_chosen = cur_k_val;
158	                break;
159	            }
160	        }
161	    }
162	    k_pivots_chosen = std::min(k_pivots_chosen, N_items_global);
163	    if (N_items_global == 0) k_pivots_chosen = 0;
164	
165	    std::vector<int> pivot_item_indices(k_pivots_chosen);
166	    if (k_pivots_chosen > 0) {
167	        std::vector<int> all_item_indices_temp(N_items_global);
168	        std::iota(all_item_indices_temp.begin(), all_item_indices_temp.end(), 0);
169	        std::shuffle(all_item_indices_temp.begin(), all_item_indices_temp.end(), rng_engine);
170	        for (int i = 0; i < k_pivots_chosen; ++i) pivot_item_indices[i] = all_item_indices_temp[i];
171	    }
172	
173	    std::vector<int> sorted_pivot_item_indices = pivot_item_indices;
174	
175	    const int FACTOR_GT_NUM = 200;
176	    const int FACTOR_LT_NUM = 50;
177	    const int FACTOR_XJ_FALLBACK_NUM = 100;
178	
179	    if (k_pivots_chosen == 0) {
180	        for (int i = 0; i < N_items_global; ++i) estimated_weights[i] = BASE_WEIGHT;
181	    } else if (k_pivots_chosen == 1) {
182	        estimated_weights[pivot_item_indices[0]] = BASE_WEIGHT;
183	        for (int i = 0; i < N_items_global; ++i) {
184	            if (i == pivot_item_indices[0]) continue;
185	            char res = compare_single_items(i, pivot_item_indices[0]);
186	            if (res == '=') estimated_weights[i] = BASE_WEIGHT;
187	            else if (res == '<') estimated_weights[i] = std::max(1LL, BASE_WEIGHT * FACTOR_LT_NUM / 100);
188	            else estimated_weights[i] = std::max(1LL, BASE_WEIGHT * FACTOR_GT_NUM / 100);
189	        }
190	    } else {
191	        merge_sort_items(sorted_pivot_item_indices, 0, k_pivots_chosen - 1);
192	
193	        int p0_idx = sorted_pivot_item_indices[0];
194	        estimated_weights[p0_idx] = BASE_WEIGHT;
195	
196	        int p1_idx = sorted_pivot_item_indices[1];
197	        char res_p1_vs_p0 = compare_single_items(p1_idx, p0_idx);
198	        if (res_p1_vs_p0 == '=') {
199	            estimated_weights[p1_idx] = estimated_weights[p0_idx];
200	        } else if (res_p1_vs_p0 == '<') {
201	            estimated_weights[p1_idx] = std::max(1LL, estimated_weights[p0_idx] * FACTOR_LT_NUM / 100);
202	        } else {
203	            estimated_weights[p1_idx] = std::max(1LL, estimated_weights[p0_idx] * FACTOR_GT_NUM / 100);
204	        }
205	        if (estimated_weights[p1_idx] < estimated_weights[p0_idx]) {
206	            estimated_weights[p1_idx] = estimated_weights[p0_idx];
207	        }
208	        if (res_p1_vs_p0 == '>' && estimated_weights[p1_idx] == estimated_weights[p0_idx]) {
209	            estimated_weights[p1_idx] = estimated_weights[p0_idx] + 1;
210	        }
211	
212	        const long long MAX_XJ_INITIAL_HIGH_BOUND = BASE_WEIGHT * (1LL * N_items_global / std::max(1, D_groups_global) + 10);
213	
214	        for (int j = 2; j < k_pivots_chosen; ++j) {
215	            int current_pivot_idx = sorted_pivot_item_indices[j];
216	            int prev_pivot_idx = sorted_pivot_item_indices[j - 1];
217	
218	            char res_curr_vs_prev = compare_single_items(current_pivot_idx, prev_pivot_idx);
219	            if (res_curr_vs_prev == '=') {
220	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx];
221	            } else if (res_curr_vs_prev == '<') {
222	                estimated_weights[current_pivot_idx] = std::max(1LL, estimated_weights[prev_pivot_idx] * FACTOR_LT_NUM / 100);
223	            } else {
224	                long long X_low_bound_val = 1;
225	                long long X_high_bound_val = MAX_XJ_INITIAL_HIGH_BOUND;
226	                bool x_low_modified = false;
227	                bool x_high_modified = false;
228	
229	                int s_search_low_arr_idx = 0, s_search_high_arr_idx = j - 2;
230	                int num_s_candidates = (s_search_high_arr_idx - s_search_low_arr_idx + 1);
231	                int queries_for_this_Xj = 0;
232	                if (num_s_candidates > 0) {
233	                    queries_for_this_Xj = static_cast<int>(std::ceil(estimate_log2(static_cast<double>(num_s_candidates))));
234	                    if (num_s_candidates == 1) queries_for_this_Xj = 1;
235	                }
236	
237	                for (int bs_iter = 0; bs_iter < queries_for_this_Xj && queries_made < Q_total_global; ++bs_iter) {
238	                    if (s_search_low_arr_idx > s_search_high_arr_idx) break;
239	                    int s_mid_arr_idx = s_search_low_arr_idx + (s_search_high_arr_idx - s_search_low_arr_idx) / 2;
240	                    int item_s_aux_idx = sorted_pivot_item_indices[s_mid_arr_idx];
241	
242	                    char res_1v2 = compare_1v2_items_specific(current_pivot_idx, prev_pivot_idx, item_s_aux_idx);
243	                    if (res_1v2 == '=') {
244	                        X_low_bound_val = X_high_bound_val = estimated_weights[item_s_aux_idx];
245	                        x_low_modified = x_high_modified = true;
246	                        break;
247	                    } else if (res_1v2 == '<') {
248	                        X_high_bound_val = estimated_weights[item_s_aux_idx];
249	                        x_high_modified = true;
250	                        s_search_high_arr_idx = s_mid_arr_idx - 1;
251	                    } else {
252	                        X_low_bound_val = estimated_weights[item_s_aux_idx];
253	                        x_low_modified = true;
254	                        s_search_low_arr_idx = s_mid_arr_idx + 1;
255	                    }
256	                }
257	
258	                long long estimated_X_j;
259	                if (x_low_modified && !x_high_modified) {
260	                    estimated_X_j = X_low_bound_val * FACTOR_GT_NUM / 100;
261	                } else if (!x_low_modified && x_high_modified) {
262	                    estimated_X_j = X_high_bound_val * FACTOR_LT_NUM / 100;
263	                } else if (x_low_modified && x_high_modified) {
264	                    estimated_X_j = (X_low_bound_val + X_high_bound_val) / 2;
265	                } else {
266	                    estimated_X_j = estimated_weights[prev_pivot_idx] * FACTOR_XJ_FALLBACK_NUM / 100;
267	                    if (estimated_weights[prev_pivot_idx] > 0 && estimated_X_j == 0) estimated_X_j = 1;
268	                    else if (estimated_weights[prev_pivot_idx] == 0) {
269	                        estimated_X_j = std::max(1LL, BASE_WEIGHT * FACTOR_XJ_FALLBACK_NUM / 100);
270	                    }
271	                }
272	                estimated_X_j = std::max(1LL, estimated_X_j);
273	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx] + estimated_X_j;
274	            }
275	            if (estimated_weights[current_pivot_idx] < estimated_weights[prev_pivot_idx]) {
276	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx];
277	            }
278	            if (res_curr_vs_prev == '>' && estimated_weights[current_pivot_idx] == estimated_weights[prev_pivot_idx]) {
279	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx] + 1;
280	            }
281	        }
282	
283	        // Estimate weights for non-pivot items
284	        for (int i = 0; i < N_items_global; ++i) {
285	            bool is_pivot_flag = false;
286	            for (int p_idx_val = 0; p_idx_val < k_pivots_chosen; ++p_idx_val) {
287	                if (sorted_pivot_item_indices[p_idx_val] == i) { is_pivot_flag = true; break; }
288	            }
289	            if (is_pivot_flag) continue;
290	
291	            int bs_low_arr_idx = 0, bs_high_arr_idx = k_pivots_chosen - 1;
292	            int found_pivot_idx_for_eq = -1;
293	
294	            while (bs_low_arr_idx <= bs_high_arr_idx) {
295	                if (queries_made >= Q_total_global && found_pivot_idx_for_eq == -1) break;
296	                int mid_p_arr_idx = bs_low_arr_idx + (bs_high_arr_idx - bs_low_arr_idx) / 2;
297	                char res_item_vs_p = compare_single_items(i, sorted_pivot_item_indices[mid_p_arr_idx]);
298	                if (res_item_vs_p == '=') { found_pivot_idx_for_eq = mid_p_arr_idx; break; }
299	                else if (res_item_vs_p == '<') { bs_high_arr_idx = mid_p_arr_idx - 1; }
300	                else { bs_low_arr_idx = mid_p_arr_idx + 1; }
301	            }
302	
303	            if (found_pivot_idx_for_eq != -1) {
304	                estimated_weights[i] = estimated_weights[sorted_pivot_item_indices[found_pivot_idx_for_eq]];
305	                continue;
306	            }
307	
308	            int insert_pos_arr_idx = bs_low_arr_idx;
309	            if (insert_pos_arr_idx == 0) {
310	                long long w_p0 = estimated_weights[sorted_pivot_item_indices[0]];
311	                if (k_pivots_chosen >= 2) {
312	                    long long w_p1 = estimated_weights[sorted_pivot_item_indices[1]];
313	                    if (w_p1 > w_p0 && w_p0 > 0 && w_p1 != 0) {
314	                        estimated_weights[i] = std::max(1LL, w_p0 * w_p0 / w_p1);
315	                    } else {
316	                        estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
317	                    }
318	                } else {
319	                    estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
320	                }
321	            } else if (insert_pos_arr_idx == k_pivots_chosen) {
322	                long long w_pk_1 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen - 1]];
323	                if (k_pivots_chosen >= 2) {
324	                    long long w_pk_2 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen - 2]];
325	                    if (w_pk_1 > w_pk_2 && w_pk_2 > 0) {
326	                        estimated_weights[i] = std::max(1LL, w_pk_1 * w_pk_1 / w_pk_2);
327	                    } else {
328	                        estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
329	                    }
330	                } else {
331	                    estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
332	                }
333	            } else {
334	                long long w_prev_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx - 1]];
335	                long long w_next_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx]];
336	                if (w_prev_p > 0 && w_next_p > 0) {
337	                    estimated_weights[i] = static_cast<long long>(std::sqrt(static_cast<double>(w_prev_p) * w_next_p));
338	                } else {
339	                    estimated_weights[i] = (w_prev_p + w_next_p) / 2;
340	                }
341	                estimated_weights[i] = std::max(w_prev_p, estimated_weights[i]);
342	                estimated_weights[i] = std::min(w_next_p, estimated_weights[i]);
343	            }
344	            if (estimated_weights[i] <= 0) estimated_weights[i] = 1;
345	        }
346	    }
347	
348	    for (int i = 0; i < N_items_global; ++i) {
349	        if (estimated_weights[i] <= 0) estimated_weights[i] = BASE_WEIGHT;
350	    }
351	
352	    // --- Partitioning Phase: LPT greedy + SA ---
353	    std::vector<int> assignment_array(N_items_global);
354	    std::vector<long long> group_sums_array(D_groups_global, 0);
355	    long long total_sum_est_val = 0;
356	    std::vector<std::vector<int>> group_items_indices(D_groups_global);
357	    std::vector<int> item_pos_in_group_vector(N_items_global);
358	
359	    std::vector<std::pair<long long, int>> items_sorted_for_greedy(N_items_global);
360	    for (int i = 0; i < N_items_global; ++i) {
361	        items_sorted_for_greedy[i] = {-estimated_weights[i], i};
362	        total_sum_est_val += estimated_weights[i];
363	    }
364	    std::sort(items_sorted_for_greedy.begin(), items_sorted_for_greedy.end());
365	
366	    for (int i = 0; i < N_items_global; ++i) {
367	        int item_idx = items_sorted_for_greedy[i].second;
368	        long long item_w = estimated_weights[item_idx];
369	        int best_grp = 0;
370	        long long min_sum = group_sums_array[0];
371	        for (int j = 1; j < D_groups_global; ++j) {
372	            if (group_sums_array[j] < min_sum) {
373	                min_sum = group_sums_array[j];
374	                best_grp = j;
375	            }
376	        }
377	        assignment_array[item_idx] = best_grp;
378	        group_sums_array[best_grp] += item_w;
379	        group_items_indices[best_grp].push_back(item_idx);
380	        item_pos_in_group_vector[item_idx] = group_items_indices[best_grp].size() - 1;
381	    }
382	
383	    double current_sum_sq_group_totals = 0;
384	    for (long long s : group_sums_array) {
385	        current_sum_sq_group_totals += static_cast<double>(s) * s;
386	    }
387	    double current_var = calculate_variance_from_sums(current_sum_sq_group_totals, static_cast<double>(total_sum_est_val), D_groups_global);
388	
389	    // SA on estimated weights
390	    double T = std::max(1.0, current_var * 0.25);
391	    if (current_var < 1e-9 && total_sum_est_val > 0) {
392	        T = std::max(1.0, static_cast<double>(total_sum_est_val) / std::max(1, N_items_global) * 0.1);
393	    }
394	    if (D_groups_global <= 1) T = 0;
395	
396	    std::uniform_real_distribution<double> unif_dist(0.0, 1.0);
397	    int sa_iters_count = 0;
398	    int no_improvement_streak = 0;
399	    const int REHEAT_THRESH = N_items_global * 15;
400	    const int CHECK_TIME_INTERVAL = 256;
401	
402	    // Run SA - the refinement phase is very fast (just I/O) so give SA most of the time
403	    std::chrono::milliseconds sa_time_limit_ms(1750);
404	
405	    while (D_groups_global > 1 && N_items_global > 0) {
406	        sa_iters_count++;
407	        if (sa_iters_count % CHECK_TIME_INTERVAL == 0) {
408	            auto time_now = std::chrono::steady_clock::now();
