            char confirm = compare_groups(group_items_indices[heaviest_grp], group_items_indices[lightest_grp]);
            if (confirm != '>') break;

            // Binary search for optimal item to move from heavy to light
            // Sort items in heavy group by estimated weight
            std::vector<int> heavy_items_sorted = group_items_indices[heaviest_grp];
            std::sort(heavy_items_sorted.begin(), heavy_items_sorted.end(), [&](int a, int b) {
                return estimated_weights[a] < estimated_weights[b];
