                    int mid = lo + (hi - lo) / 2;
                    int candidate = heavy_items_sorted[mid];

                    // Build heavy group without candidate
                    std::vector<int> heavy_without;
                    heavy_without.reserve(n_heavy - 1);
                    for (int item : group_items_indices[heaviest_grp]) {
                        if (item != candidate) heavy_without.push_back(item);
                    }

                    // Build light group with candidate
                    std::vector<int> light_with = group_items_indices[lightest_grp];
                    light_with.push_back(candidate);

                    if (heavy_without.empty()) {
                        // Moving the only item — always do it
                        best_item_idx = mid;
                        break;
                    }

                    char cmp = compare_groups(heavy_without, light_with);

                    if (cmp == '=') {
                        best_item_idx = mid;
                        break;
                    } else if (cmp == '>') {
                        // Item too small, need bigger
                        last_gt = mid;
                        lo = mid + 1;
                    } else {
                        // Item too big, need smaller
                        first_lt = mid;
                        hi = mid - 1;
                    }
                }

                if (best_item_idx == -1) {
                    if (last_gt >= 0 && first_lt < n_heavy) {
                        // Prefer under-correction (last_gt) to avoid overshooting
                        // Over-correction creates new imbalance; under-correction can be fixed next round
                        best_item_idx = last_gt;
                    } else if (last_gt >= 0) {
                        best_item_idx = last_gt;
                    } else if (first_lt < n_heavy) {
                        best_item_idx = first_lt;
                    } else {
                        best_item_idx = n_heavy / 2;
                    }
                }
            }

            int best_move_item = heavy_items_sorted[best_item_idx];

            // Verify the move actually helps: check heavy > light still after move candidate
            // (We already confirmed heavy > light, so any move that doesn't overshoot helps)
            // If binary search found '=' that's perfect. If last_gt was found, moving that
            // item keeps heavy still heaviest but reduces gap. If first_lt, it flips —
            // we prefer last_gt in that case to avoid overshooting.
            // Recheck: if we have both last_gt and first_lt, prefer last_gt (under-correct rather than over-correct)
            if (best_item_idx == -1) break;

            // For under-correction preference: if we found the transition, prefer last_gt
            // unless first_lt gives equality or near-equality
            // (Already handled above — if last_gt exists and first_lt exists, we pick based on estimate)

            // Perform move
            long long item_w = estimated_weights[best_move_item];
            group_sums_array[heaviest_grp] -= item_w;
            group_sums_array[lightest_grp] += item_w;
            assignment_array[best_move_item] = lightest_grp;

            int pos = item_pos_in_group_vector[best_move_item];
            int last_item = group_items_indices[heaviest_grp].back();
            if (best_move_item != last_item) {
                group_items_indices[heaviest_grp][pos] = last_item;
                item_pos_in_group_vector[last_item] = pos;
            }
            group_items_indices[heaviest_grp].pop_back();
            group_items_indices[lightest_grp].push_back(best_move_item);
            item_pos_in_group_vector[best_move_item] = group_items_indices[lightest_grp].size() - 1;
        }
    }

    // Exhaust any remaining queries
    while (queries_made < Q_total_global) {
        perform_query_actual({0}, {1});
    }

    for (int i = 0; i < N_items_global; ++i) {
        std::cout << assignment_array[i] << (i == N_items_global - 1 ? "" : " ");
    }
