if (n_light >= 1 && queries_made + 3 <= Q_total_global) {
    // Sort light group items by estimated weight (descending)
    // We want to find an item from light to send back to heavy
    // that compensates for the overshoot
    std::vector<int> light_items_sorted = group_items_indices[lightest_grp];
    std::sort(light_items_sorted.begin(), light_items_sorted.end(), [&](int a, int b) {
        return estimated_weights[a] < estimated_weights[b];
    });

    // Binary search in light group: find item to swap back
    // After swap: heavy gets comp_item, loses overshoot_item
    //             light gets overshoot_item, loses comp_item
    // We want: (heavy - overshoot + comp) vs (light + overshoot - comp) to be '=' or close
    int swap_best = -1;
    int s_last_lt = -1;
    int s_first_gt = n_light;
    int s_lo = 0, s_hi = n_light - 1;

    while (s_lo <= s_hi && queries_made < Q_total_global) {
        int s_mid = s_lo + (s_hi - s_lo) / 2;
        int comp_item = light_items_sorted[s_mid];

        // Build new heavy: heavy - overshoot + comp
        std::vector<int> new_heavy;
        new_heavy.reserve(n_heavy);
        for (int item : group_items_indices[heaviest_grp]) {
            if (item != overshoot_item) new_heavy.push_back(item);
        }
        new_heavy.push_back(comp_item);

        // Build new light: light + overshoot - comp
        std::vector<int> new_light;
        new_light.reserve(n_light);
        for (int item : group_items_indices[lightest_grp]) {
            if (item != comp_item) new_light.push_back(item);
        }
        new_light.push_back(overshoot_item);

        char cmp2 = compare_groups(new_heavy, new_light);
        if (cmp2 == '=') {
            swap_best = s_mid;
            break;
        } else if (cmp2 == '<') {
            // comp too small, need bigger from light
            s_last_lt = s_mid;
            s_lo = s_mid + 1;
        } else {
            // comp too big, need smaller
